class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        long long res = 0;
        for (int i = 1; i <= k; i++) {
            long long ways = 1;
            for (int j = 1; j <= n - 2; j++) {
                if (i == k) ways *= j + 1;
                else ways *= j;
            }
            res += ways;
        }
        return res;
    }
};
```

